('computer-science:2-2-3b-arrays:match:2c1b8104', 'computer-science', 'computer-science:2-2-3b-arrays', '2.2.3b Arrays', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Index”?", "options": ["A loop placed inside another loop, used to visit every element of a 2D array", "The numbered position of an element within an array, starting from 0", "A loop that visits every index of an n-element array in turn", "Declares a 2D array arranged as a grid with 3 rows and 4 columns"]}'::jsonb, '{"answer": 1, "explain": "“Index” means: The numbered position of an element within an array, starting from 0"}'::jsonb),
